import { styled } from 'styled-components'

const StyledMain = styled.main`
  padding-top: 80px;
  padding-bottom: 120px;

  display: grid;
  grid-template-columns: 1fr 1fr;
  column-gap: 80px;
  row-gap: 48px;

  width: min-content;
  margin: auto;
`
export default StyledMain
